ERModelExpressionItem.ExpressionAsString:
FIRSTORNULL(
    FILTER(VendInvoiceJour, 
        AND(
            VendInvoiceJour.LedgerVoucher = '$TaxTransDetailsJoinGroup'.aggregated.'$VendTransByLedgerJournalTrans'.Voucher,
            VendInvoiceJour.InvoiceAccount = '$TaxTransDetailsJoinGroup'.aggregated.'$VendTransByLedgerJournalTrans'.AccountNum,
            VendInvoiceJour.InvoiceDate = '$TaxTransDetailsJoinGroup'.aggregated.'$VendTransByLedgerJournalTrans'.TransDate
        )
    )
)

IF('$TaxTransDetailsJoinGroup'.grouped.SourceTableId = ProjInvoiceItemTableId,
    FIRSTORNULL(
        FILTER(ProjInvoiceItemDetail, 
            ProjInvoiceItemDetail.InvoiceRefRecId = '$TaxTransDetailsJoinGroup'.grouped.SourceRecId
        )
    ),
    FIRSTORNULL(FILTER(ProjInvoiceItemDetail, FALSE))
)
